### --- NEURAL NETWORK STUFF ---
input_size = 196
hidden_size = 64
output_size = 1 #one number for the output!
q_output_size = 2


def init_params(key, input_size, hidden_size, output_size):
    """Initialize network parameters (weights and biases)"""
    # Weights and biases for the first layer (input to hidden)
    key, subkey = jax.random.split(key)
    W1 = jax.random.normal(subkey, (input_size, hidden_size)) * 0.1
    b1 = jnp.zeros(hidden_size)

    # Weights and biases for the second layer (hidden to output)
    key, subkey = jax.random.split(key)
    W2 = jax.random.normal(subkey, (hidden_size, hidden_size)) * 0.1
    b2 = jnp.zeros(hidden_size)

    # Weights and biases for the second layer (hidden to output)
    key, subkey = jax.random.split(key)
    W3 = jax.random.normal(subkey, (hidden_size, output_size)) * 0.1
    b3 = jnp.zeros(output_size)

    return (W1, b1, W2, b2, W3, b3)

@jax.jit
def value(params, board):
    W1, b1, W2, b2, W3, b3 = params
    one_hot_neg1 = (board == -1)  # Where board is -1
    one_hot_0 = (board == 0)     # Where board is 0
    one_hot_1 = (board == 1)     # Where board is 1
    one_hot_2 = (board == 2)      # Where board is 2
                                
    # Stack along a new axis to form a one-hot encoding (last dimension will be 4)
    one_hot = jnp.stack([one_hot_neg1, one_hot_1, one_hot_0, one_hot_2], axis=-1)  # Shape (..., N_ROWS, N_COLS, 4)

    # Calculate potential three-in-a-lines and two-in-a-lines for each player
    p1_potential = jnp.logical_or((board==1), (board==0))
    p1_potential_VP = which_three_in_a_line(p1_potential)
    p1_potential_twos = which_three_in_a_line(p1_potential, TWO_IN_A_ROW_MASK)

    p2_potential = jnp.logical_or((board==2), (board==0))
    p2_potential_VP = which_three_in_a_line(p2_potential)
    p2_potential_twos = which_three_in_a_line(p2_potential, TWO_IN_A_ROW_MASK)

    # Flatten the last three dimensions into a single vector using einops
    flat_one_hot = rearrange(one_hot, "... N_ROWS N_COLS C -> ... (N_ROWS N_COLS C)")
    x = jnp.concatenate([flat_one_hot, p1_potential_VP, p1_potential_twos, p2_potential_VP, p2_potential_twos], axis=-1)

    first = jnp.dot(x, W1) + b1
    hidden1 = jnp.dot(jax.nn.relu(first), W2) + b2
    output = 2.0*jax.nn.sigmoid(jnp.dot(jax.nn.relu(hidden1), W3) + b3) - 1.0
    clean_output = rearrange(output, "... 1 -> ...")
    return clean_output

@jax.jit
def roll_again_value(params, board):
  W1, b1, W2, b2, W3, b3 = params
  one_hot_neg1 = (board == -1)  # Where board is -1
  one_hot_0 = (board == 0)     # Where board is 0
  one_hot_1 = (board == 1)     # Where board is 1
  one_hot_2 = (board == 2)      # Where board is 2

  # Stack along a new axis to form a one-hot encoding (last dimension will be 4)
  one_hot = jnp.stack([one_hot_neg1, one_hot_1, one_hot_0, one_hot_2], axis=-1)  # Shape (..., N_ROWS, N_COLS, 4)

  # Calculate potential three-in-a-lines and two-in-a-lines for each player
  p1_potential = jnp.logical_or((board==1), (board==0))
  p1_potential_VP = which_three_in_a_line(p1_potential)
  p1_potential_twos = which_three_in_a_line(p1_potential, TWO_IN_A_ROW_MASK)

  p2_potential = jnp.logical_or((board==2), (board==0))
  p2_potential_VP = which_three_in_a_line(p2_potential)
  p2_potential_twos = which_three_in_a_line(p2_potential, TWO_IN_A_ROW_MASK)

  # Flatten the last three dimensions into a single vector using einops
  flat_one_hot = rearrange(one_hot, "... N_ROWS N_COLS C -> ... (N_ROWS N_COLS C)")
  x = jnp.concatenate([flat_one_hot, p1_potential_VP, p1_potential_twos, p2_potential_VP, p2_potential_twos], axis=-1)

  first = jnp.dot(x, W1) + b1
  hidden1 = jnp.dot(jax.nn.relu(first), W2) + b2
  output = 2.0*jax.nn.sigmoid(jnp.dot(jax.nn.relu(hidden1), W3) + b3) - 1.0
  return output

key = jax.random.PRNGKey(42)

def dict_to_params(params_dict):
    """Convert a dictionary back to JAX parameter tuples"""
    # Verify all required keys exist
    required_keys = {"W1", "b1", "W2", "b2", "W3", "b3"}
    if not required_keys.issubset(params_dict.keys()):
        missing = required_keys - params_dict.keys()
        raise ValueError(f"Missing keys in dictionary: {missing}")

    # Convert lists back to JAX arrays with proper dtype
    return (
        jnp.array(params_dict["W1"], dtype=jnp.float32),
        jnp.array(params_dict["b1"], dtype=jnp.float32),
        jnp.array(params_dict["W2"], dtype=jnp.float32),
        jnp.array(params_dict["b2"], dtype=jnp.float32),
        jnp.array(params_dict["W3"], dtype=jnp.float32),
        jnp.array(params_dict["b3"], dtype=jnp.float32),
    )

params = dict_to_params(params_dict)
q_params = dict_to_params(q_params_dict)

optimizer = optax.adam(learning_rate=1e-3) #rate between 1e-2 and 1e-3 is a good choice!
optimizer_state = optimizer.init(params)

q_optimizer = optax.adam(learning_rate=1e-3) #rate between 1e-2 and 1e-3 is a good choice!
q_optimizer_state = q_optimizer.init(q_params)

def loss(params,board, actual, which_ones):
  vals = value(params, board);
  squared_error = (vals - actual)**2
  masked_losses = squared_error * which_ones
  return jnp.sum(masked_losses) / jnp.sum(which_ones)

def action_loss(params, board, actual, actions, which_ones):
  q_vals = roll_again_value(params, board)

  # 2. one-hot mask: shape (B,2), with a 1 at the chosen-action index
  mask = jax.nn.one_hot(actions, num_classes=2)

  # 3. elementwise × then sum over the action dim → shape (B,)
  #    keeps only the Q of the taken action
  chosen_q_val = jnp.sum(q_vals * mask, axis=-1)

  squared_error = (chosen_q_val - actual)**2
  masked_losses = squared_error * which_ones
  return jnp.sum(masked_losses) / jnp.sum(which_ones)

loss_grad = jax.grad(loss)
q_loss_grad = jax.grad(action_loss)


def my_AI(key, moves, legal, board):
  '''Simplest possible AI that returns a random legal move and chooses to roll again or not purely at random'''
  #Input: key is a JAX random key object
  #  moves is shape (N_POSSIBLE, N_ROW, N_COL) with the possible moves
  #  legal is shape (N_POSSIBLE) with whether or not each move is possible
  #  board is shape (N_ROW, N_COL) with the current board (i.e. the situation *before* this turn)

  # Get values
  vals = value(params, moves)

  # Remove illegal moves
  vals = jnp.where(legal, vals, -jnp.inf)
  move_ix = jnp.argmax(vals)
  roll_again_vals = roll_again_value(q_params, board)
  action_ix = jnp.argmax(roll_again_vals)

  return move_ix, action_ix